#!/usr/bin/env python3
"""
deploy_v19_34_220.py - FUNDAMENTAL PILLAR: catalyst from the news_articles cache

The catalyst component (30pct of the Fundamental pillar) was floored at 40 ("no
catalyst") for ~100pct of alerts. Root cause (diag_news_catalyst.py): the pillar
called the LIVE news_service.get_ticker_news per alert, which tries IB historical
news FIRST with a 30s timeout (hangs in this ib-direct deployment) and then
Finnhub (rate-limited ~60/min) - unusable across 100+ alerts/scan. Meanwhile the
local `news_articles` cache (Finnhub+Yahoo collectors, ~92k docs, FinBERT-scored,
fresh today) sat unused.

v220: the pillar now reads recent (<=72h) news for the symbol directly from
`news_articles` (fast indexed lookup, no hang, no rate limit) and derives
has_recent_news + news_sentiment from the FinBERT `sentiment` dict. Lifts
catalyst off the 40 floor (50 neutral / 65 directional). Also creates the
{symbol:1, datetime:-1} index on news_articles.

SAFETY: checksum-guarded full-file replace (writes ONLY if on-disk file matches
the pre-patch HEAD sha OR already carries the v220 marker; aborts on drift).
Idempotent, transactional, runs the test, commits + pushes BEFORE restart.

RUN ON THE DGX:
  curl -s https://paste.rs/XXXXX -o /tmp/deploy_v19_34_220.py
  python3 /tmp/deploy_v19_34_220.py
  ./start_backend.sh --force
"""
import os, base64, hashlib, shutil, subprocess, sys, py_compile

REPO=os.path.expanduser("~/Trading-and-Analysis-Platform")
if not os.path.isdir(REPO): REPO=os.getcwd()
SVC=os.path.join(REPO,"backend","services","tqs","fundamental_quality.py")
TEST=os.path.join(REPO,"backend","tests","test_v19_34_220_fundamental_news_cache.py")

MARKER="v19.34.220"
PREPATCH_SHA="78e0326fb8eb5074c27add406cb9f6424af41614ffe7d0021f4bc82f275382e1"
NEW_SVC_SHA="db3cabdf0fa518deacedcff31ebbbb6deeb674b1ff750ea8a73695d400011b3c"
SVC_B64=""
TEST_B64=""


def fail(m):
    print("\n[FAIL] "+m); sys.exit(1)


def main():
    print("== deploy_v19_34_220 ==\nrepo: "+REPO)
    if not os.path.isfile(SVC): fail("target not found: "+SVC)
    cur=open(SVC,"rb").read(); cur_sha=hashlib.sha256(cur).hexdigest()
    new_bytes=base64.b64decode(SVC_B64)
    assert hashlib.sha256(new_bytes).hexdigest()==NEW_SVC_SHA, "payload corrupt"

    if MARKER in cur.decode("utf-8","ignore"):
        print("[ok] already patched (v220 marker) - skipping file write.")
    elif cur_sha==PREPATCH_SHA:
        shutil.copy2(SVC,SVC+".v220.bak"); open(SVC,"wb").write(new_bytes)
        try:
            py_compile.compile(SVC,doraise=True)
        except py_compile.PyCompileError as e:
            shutil.copy2(SVC+".v220.bak",SVC); fail("py_compile failed, rolled back: "+str(e))
        os.remove(SVC+".v220.bak")
        print("[ok] fundamental_quality.py replaced + compiles clean.")
    else:
        fail("on-disk fundamental_quality.py matches NEITHER pre-patch HEAD sha NOR "
             "v220 marker (sha="+cur_sha[:12]+"). Drift - aborting WITHOUT changes.")

    os.makedirs(os.path.dirname(TEST),exist_ok=True)
    open(TEST,"wb").write(base64.b64decode(TEST_B64))
    print("[ok] wrote test file")

    # one-time index for the per-alert {symbol, datetime} lookup
    try:
        from pymongo import MongoClient
        mu=os.environ.get("MONGO_URL")
        if mu:
            db=MongoClient(mu,serverSelectionTimeoutMS=4000)[os.environ.get("DB_NAME","tradecommand")]
            db["news_articles"].create_index([("symbol",1),("datetime",-1)])
            print("[ok] ensured news_articles {symbol:1, datetime:-1} index")
    except Exception as e:
        print("[warn] could not create index (non-fatal):",e)

    print("\n== pytest ==")
    r=subprocess.run([sys.executable,"-m","pytest",TEST,"-q"],cwd=os.path.join(REPO,"backend"))
    if r.returncode!=0: fail("pytest failed - NOT committing.")
    print("[ok] tests green.")

    print("\n== git commit + push ==")
    subprocess.run(["git","add","-A"],cwd=REPO)
    cm=subprocess.run(["git","commit","-m",
        "v19.34.220 Fundamental pillar: catalyst from news_articles cache "
        "(replace hanging live get_ticker_news) + symbol/datetime index"],cwd=REPO)
    if cm.returncode==0:
        subprocess.run(["git","push"],cwd=REPO); print("[ok] committed + pushed.")
    else:
        print("[info] nothing to commit - skipping push.")

    print("\n[DONE] Restart backend:  ./start_backend.sh --force")
    print("Then re-run:  python3 /tmp/diag_tqs_pillar_breakdown.py --since-min 15")
    print("FUNDAMENTAL pillar should SPREAD WIDER (catalyst now 40/50/65, not flat 40).")


if __name__=="__main__":
    main()
